import { Test, TestingModule } from '@nestjs/testing';
import { ConflictException, UnauthorizedException } from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { PrismaService } from '../../../shared/prisma/prisma.service';
import { AuthService } from '../auth.service';
import { RegisterDto } from '../dto/register.dto';
import { LoginDto } from '../dto/login.dto';
import { UserRole } from '../../../shared/enums';
import * as bcrypt from 'bcryptjs';
import { describe, beforeEach, it, expect, vi } from 'vitest';

// Mock de bcrypt
vi.mock('bcryptjs', () => ({
  hash: vi.fn(),
  compare: vi.fn(),
}));

describe('AuthService', () => {
  let authService: AuthService;
  let prismaService: PrismaService;
  let jwtService: JwtService;

  const mockPrismaService = {
    user: {
      findUnique: vi.fn(),
      create: vi.fn(),
      findFirst: vi.fn(),
    },
    $connect: vi.fn(),
    $disconnect: vi.fn(),
    $on: vi.fn(),
    $use: vi.fn(),
  };

  const mockJwtService = {
    signAsync: vi.fn(),
    verifyAsync: vi.fn(),
  };

  beforeEach(async () => {
    // Instanciar manualmente el servicio para evitar problemas con el TestingModule
    authService = new AuthService(
      mockPrismaService as any,
      mockJwtService as any,
    );
    prismaService = mockPrismaService as any;
    jwtService = mockJwtService as any;

    vi.clearAllMocks();
  });

  describe('register', () => {
    it('deberÃ­a registrar un usuario exitosamente', async () => {
      const registerDto: RegisterDto = {
        email: 'test@example.com',
        password: 'password123',
        name: 'Test User',
        role: UserRole.USER,
      };

      const hashedPassword = 'hashedPassword123';
      const mockUser = {
        id: 'user-id-123',
        email: registerDto.email,
        name: registerDto.name,
        role: registerDto.role,
        passwordHash: hashedPassword,
        provider: 'LOCAL',
        createdAt: new Date(),
        updatedAt: new Date(),
      };

      const mockTokens = {
        accessToken: 'access-token-123',
        refreshToken: 'refresh-token-123',
        expiresIn: 3600,
        tokenType: 'Bearer',
        user: {
          id: mockUser.id,
          email: mockUser.email,
          name: mockUser.name,
          role: mockUser.role,
        },
      };

      // Mock de bcrypt.hash
      (bcrypt.hash as any).mockResolvedValue(hashedPassword);

      // Mock de findUnique (usuario no existe)
      mockPrismaService.user.findUnique.mockResolvedValue(null);

      // Mock de create
      mockPrismaService.user.create.mockResolvedValue(mockUser);

      // Mock de generateTokens
      vi.spyOn(authService as any, 'generateTokens').mockResolvedValue(
        mockTokens,
      );

      const result = await authService.register(registerDto);

      expect(mockPrismaService.user.findUnique).toHaveBeenCalledWith({
        where: { email: registerDto.email },
      });
      expect(bcrypt.hash).toHaveBeenCalledWith(registerDto.password, 12);
      expect(mockPrismaService.user.create).toHaveBeenCalledWith({
        data: {
          email: registerDto.email,
          passwordHash: hashedPassword,
          name: registerDto.name,
          role: registerDto.role,
          provider: 'LOCAL',
        },
      });
      expect(result).toEqual(mockTokens);
    });

    it('deberÃ­a lanzar ConflictException si el email ya estÃ¡ registrado', async () => {
      const registerDto: RegisterDto = {
        email: 'existing@example.com',
        password: 'password123',
        name: 'Existing User',
        role: UserRole.USER,
      };

      const existingUser = {
        id: 'existing-id',
        email: registerDto.email,
        name: 'Existing User',
      };

      mockPrismaService.user.findUnique.mockResolvedValue(existingUser);

      await expect(authService.register(registerDto)).rejects.toThrow(
        ConflictException,
      );
      await expect(authService.register(registerDto)).rejects.toThrow(
        'El email ya estÃ¡ registrado',
      );

      expect(mockPrismaService.user.findUnique).toHaveBeenCalledWith({
        where: { email: registerDto.email },
      });
      expect(mockPrismaService.user.create).not.toHaveBeenCalled();
    });
  });

  describe('login', () => {
    it('deberÃ­a hacer login exitosamente con credenciales vÃ¡lidas', async () => {
      const loginDto: LoginDto = {
        email: 'test@example.com',
        password: 'password123',
      };

      const mockUser = {
        id: 'user-id-123',
        email: loginDto.email,
        name: 'Test User',
        role: UserRole.USER,
        passwordHash: 'hashedPassword123',
        provider: 'LOCAL',
        isActive: true,
      };

      const mockTokens = {
        accessToken: 'access-token-123',
        refreshToken: 'refresh-token-123',
        expiresIn: 3600,
        tokenType: 'Bearer',
        user: {
          id: mockUser.id,
          email: mockUser.email,
          name: mockUser.name,
          role: mockUser.role,
        },
      };

      // Mock de findUnique
      mockPrismaService.user.findUnique.mockResolvedValue(mockUser);

      // Mock de bcrypt.compare
      (bcrypt.compare as any).mockResolvedValue(true);

      // Mock de generateTokens
      vi.spyOn(authService as any, 'generateTokens').mockResolvedValue(
        mockTokens,
      );

      const result = await authService.login(loginDto);

      expect(mockPrismaService.user.findUnique).toHaveBeenCalledWith({
        where: { email: loginDto.email },
      });
      expect(bcrypt.compare).toHaveBeenCalledWith(
        loginDto.password,
        mockUser.passwordHash,
      );
      expect(result).toEqual(mockTokens);
    });

    it('deberÃ­a lanzar UnauthorizedException si el usuario no existe', async () => {
      const loginDto: LoginDto = {
        email: 'nonexistent@example.com',
        password: 'password123',
      };

      mockPrismaService.user.findUnique.mockResolvedValue(null);

      await expect(authService.login(loginDto)).rejects.toThrow(
        UnauthorizedException,
      );
      await expect(authService.login(loginDto)).rejects.toThrow(
        'Credenciales invÃ¡lidas',
      );

      expect(mockPrismaService.user.findUnique).toHaveBeenCalledWith({
        where: { email: loginDto.email },
      });
      expect(bcrypt.compare).not.toHaveBeenCalled();
    });

    it('deberÃ­a lanzar UnauthorizedException si la contraseÃ±a es incorrecta', async () => {
      const loginDto: LoginDto = {
        email: 'test@example.com',
        password: 'wrongpassword',
      };

      const mockUser = {
        id: 'user-id-123',
        email: loginDto.email,
        name: 'Test User',
        passwordHash: 'hashedPassword123',
        provider: 'LOCAL',
        isActive: true,
      };

      mockPrismaService.user.findUnique.mockResolvedValue(mockUser);
      (bcrypt.compare as any).mockResolvedValue(false);

      await expect(authService.login(loginDto)).rejects.toThrow(
        UnauthorizedException,
      );
      await expect(authService.login(loginDto)).rejects.toThrow(
        'Credenciales invÃ¡lidas',
      );

      expect(mockPrismaService.user.findUnique).toHaveBeenCalledWith({
        where: { email: loginDto.email },
      });
      expect(bcrypt.compare).toHaveBeenCalledWith(
        loginDto.password,
        mockUser.passwordHash,
      );
    });
  });

  describe('refreshToken', () => {
    it('deberÃ­a refrescar el token exitosamente', async () => {
      const refreshToken = 'valid-refresh-token';
      const mockPayload = {
        sub: 'user-id-123',
        email: 'test@example.com',
        role: UserRole.USER,
      };

      const mockUser = {
        id: mockPayload.sub,
        email: mockPayload.email,
        name: 'Test User',
        role: mockPayload.role,
        provider: 'LOCAL',
        isActive: true,
      };

      const mockTokens = {
        accessToken: 'new-access-token',
        refreshToken: 'new-refresh-token',
        expiresIn: 3600,
        tokenType: 'Bearer',
        user: {
          id: mockUser.id,
          email: mockUser.email,
          name: mockUser.name,
          role: mockUser.role,
        },
      };

      mockJwtService.verifyAsync.mockResolvedValue(mockPayload);
      mockPrismaService.user.findUnique.mockResolvedValue(mockUser);
      vi.spyOn(authService as any, 'generateTokens').mockResolvedValue(
        mockTokens,
      );

      const result = await authService.refreshToken(refreshToken);

      expect(mockJwtService.verifyAsync).toHaveBeenCalledWith(refreshToken);
      expect(mockPrismaService.user.findUnique).toHaveBeenCalledWith({
        where: { id: mockPayload.sub },
      });
      expect(result).toEqual(mockTokens);
    });

    it('deberÃ­a lanzar UnauthorizedException si el refresh token es invÃ¡lido', async () => {
      const refreshToken = 'invalid-refresh-token';

      mockJwtService.verifyAsync.mockRejectedValue(new Error('Token invÃ¡lido'));

      await expect(authService.refreshToken(refreshToken)).rejects.toThrow(
        UnauthorizedException,
      );
      await expect(authService.refreshToken(refreshToken)).rejects.toThrow(
        'Refresh token invÃ¡lido o expirado',
      );

      expect(mockJwtService.verifyAsync).toHaveBeenCalledWith(refreshToken);
      expect(mockPrismaService.user.findFirst).not.toHaveBeenCalled();
    });
  });
});

import {
  Controller,
  Post,
  Body,
  HttpCode,
  HttpStatus,
  UseGuards,
  Get,
  Req,
  Res,
  Patch,
  UseInterceptors,
  ClassSerializerInterceptor,
  UnauthorizedException,
} from '@nestjs/common';
import {
  ApiTags,
  ApiOperation,
  ApiResponse,
  ApiBearerAuth,
  ApiBody,
  ApiCookieAuth,
} from '@nestjs/swagger';
import { AuthGuard } from '@nestjs/passport';
import { AuthService } from './auth.service';
import { RegisterDto } from './dto/register.dto';
import { LoginDto } from './dto/login.dto';
import { TokensResponseDto, RefreshTokenDto } from './dto/tokens.dto';
import { ThrottlerGuard, Throttle } from '@nestjs/throttler';
import { JwtAuthGuard } from './guards/jwt-auth.guard';
import { RolesGuard } from './guards/roles.guard';
import { Roles } from './decorators/roles.decorator';
import { UserRole } from '../../shared/enums';
import { Request, Response } from 'express';
import { COOKIE_CONSTANTS, JWT_CONSTANTS } from './auth.constants';

@ApiTags('auth')
@Controller('auth')
@UseInterceptors(ClassSerializerInterceptor)
@UseGuards(ThrottlerGuard)
export class AuthController {
  constructor(private readonly authService: AuthService) {}

  @Post('register')
  @HttpCode(HttpStatus.CREATED)
  @Throttle({ default: { ttl: 60000, limit: 10 } })
  @ApiOperation({ summary: 'Registrar nuevo usuario' })
  @ApiResponse({
    status: HttpStatus.CREATED,
    description: 'Usuario registrado exitosamente',
    type: TokensResponseDto,
  })
  @ApiResponse({
    status: HttpStatus.CONFLICT,
    description: 'El email ya estÃ¡ registrado',
  })
  @ApiResponse({
    status: HttpStatus.BAD_REQUEST,
    description: 'Datos de registro invÃ¡lidos',
  })
  async register(
    @Body() registerDto: RegisterDto,
    @Res({ passthrough: true }) res: Response,
  ): Promise<{ message: string }> {
    const tokens = await this.authService.register(registerDto);

    // Configurar cookie de access token
    res.cookie(COOKIE_CONSTANTS.ACCESS_TOKEN_NAME, tokens.accessToken, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
      maxAge: 15 * 60 * 1000, // 15 minutos
    });

    // Configurar cookie de refresh token
    res.cookie(COOKIE_CONSTANTS.REFRESH_TOKEN_NAME, tokens.refreshToken, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
      maxAge: 7 * 24 * 60 * 60 * 1000, // 7 dÃ­as
    });

    return { message: 'Usuario registrado exitosamente' };
  }

  @Post('login')
  @HttpCode(HttpStatus.OK)
  @Throttle({ default: { ttl: 60000, limit: 10 } })
  @ApiOperation({ summary: 'Iniciar sesiÃ³n con email/password' })
  @ApiResponse({
    status: HttpStatus.OK,
    description: 'Login exitoso',
    type: TokensResponseDto,
  })
  @ApiResponse({
    status: HttpStatus.UNAUTHORIZED,
    description: 'Credenciales invÃ¡lidas',
  })
  @ApiResponse({
    status: HttpStatus.TOO_MANY_REQUESTS,
    description: 'Demasiados intentos de login',
  })
  async login(
    @Body() loginDto: LoginDto,
    @Req() req: Request,
    @Res({ passthrough: true }) res: Response,
  ): Promise<{ message: string }> {
    const ipAddress = req.ip;
    const tokens = await this.authService.login(loginDto, ipAddress);

    // Configurar cookie de access token
    res.cookie(COOKIE_CONSTANTS.ACCESS_TOKEN_NAME, tokens.accessToken, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
      maxAge: 15 * 60 * 1000, // 15 minutos
    });

    // Configurar cookie de refresh token
    res.cookie(COOKIE_CONSTANTS.REFRESH_TOKEN_NAME, tokens.refreshToken, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
      maxAge: 7 * 24 * 60 * 60 * 1000, // 7 dÃ­as
    });

    return { message: 'Login exitoso' };
  }

  @Post('refresh')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Refrescar access token' })
  @ApiCookieAuth('refresh_token')
  @ApiBody({ type: RefreshTokenDto })
  @ApiResponse({
    status: HttpStatus.OK,
    description: 'Token refrescado exitosamente',
    type: TokensResponseDto,
  })
  @ApiResponse({
    status: HttpStatus.UNAUTHORIZED,
    description: 'Refresh token invÃ¡lido o expirado',
  })
  async refreshToken(
    @Req() req: Request,
    @Res({ passthrough: true }) res: Response,
  ): Promise<{ message: string }> {
    const refreshToken = req.cookies?.[COOKIE_CONSTANTS.REFRESH_TOKEN_NAME];

    if (!refreshToken) {
      throw new UnauthorizedException('Refresh token no encontrado en cookies');
    }

    const tokens = await this.authService.refreshToken(refreshToken);

    // Configurar cookie de access token
    res.cookie(COOKIE_CONSTANTS.ACCESS_TOKEN_NAME, tokens.accessToken, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
      maxAge: 15 * 60 * 1000, // 15 minutos
    });

    // Configurar cookie de refresh token (renovar)
    res.cookie(COOKIE_CONSTANTS.REFRESH_TOKEN_NAME, tokens.refreshToken, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
      maxAge: 7 * 24 * 60 * 60 * 1000, // 7 dÃ­as
    });

    return { message: 'Token refrescado exitosamente' };
  }

  @Post('logout')
  @HttpCode(HttpStatus.OK)
  @UseGuards(JwtAuthGuard)
  @ApiBearerAuth()
  @ApiOperation({ summary: 'Cerrar sesiÃ³n' })
  @ApiResponse({
    status: HttpStatus.OK,
    description: 'SesiÃ³n cerrada exitosamente',
  })
  async logout(
    @Res({ passthrough: true }) res: Response,
  ): Promise<{ message: string }> {
    // Limpiar cookie de access token
    res.clearCookie(COOKIE_CONSTANTS.ACCESS_TOKEN_NAME, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
    });

    // Limpiar cookie de refresh token
    res.clearCookie(COOKIE_CONSTANTS.REFRESH_TOKEN_NAME, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
    });

    return { message: 'SesiÃ³n cerrada exitosamente' };
  }

  @Get('google')
  @ApiOperation({ summary: 'Iniciar autenticaciÃ³n con Google' })
  @ApiResponse({
    status: HttpStatus.FOUND,
    description: 'RedirecciÃ³n a Google OAuth',
  })
  async googleAuth() {
    // La redirecciÃ³n serÃ¡ manejada por Passport
    return { message: 'Redirigiendo a Google OAuth' };
  }

  @Get('google/callback')
  @UseGuards(AuthGuard('google'))
  @ApiOperation({ summary: 'Callback de Google OAuth' })
  @ApiResponse({
    status: HttpStatus.OK,
    description: 'AutenticaciÃ³n con Google exitosa',
    type: TokensResponseDto,
  })
  @ApiResponse({
    status: HttpStatus.UNAUTHORIZED,
    description: 'AutenticaciÃ³n con Google fallida',
  })
  async googleAuthCallback(
    @Req() req: any,
    @Res({ passthrough: true }) res: Response,
  ): Promise<TokensResponseDto> {
    // El usuario ya estÃ¡ autenticado por Passport
    const user = req.user;

    if (!user) {
      throw new UnauthorizedException('AutenticaciÃ³n con Google fallida');
    }

    // Generar tokens para el usuario
    const tokens = await this.authService.generateTokens(user);

    // Configurar cookie de refresh token
    const refreshToken = await this.authService.generateRefreshToken(user);

    res.cookie(COOKIE_CONSTANTS.REFRESH_TOKEN_NAME, refreshToken, {
      httpOnly: COOKIE_CONSTANTS.HTTP_ONLY,
      secure: COOKIE_CONSTANTS.SECURE,
      sameSite: COOKIE_CONSTANTS.SAME_SITE,
      path: COOKIE_CONSTANTS.PATH,
      maxAge: 7 * 24 * 60 * 60 * 1000, // 7 dÃ­as
    });

    return tokens;
  }
}

import {
  Injectable,
  UnauthorizedException,
  ConflictException,
  ForbiddenException,
} from '@nestjs/common';
import { JwtService } from '@nestjs/jwt';
import { PrismaService } from '../../shared/prisma/prisma.service';
import { RegisterDto } from './dto/register.dto';
import { LoginDto } from './dto/login.dto';
import { TokensResponseDto } from './dto/tokens.dto';
import * as bcrypt from 'bcryptjs';
import { User } from '@prisma/client';
import { UserRole } from '../../shared/enums';
import { JWT_CONSTANTS, COOKIE_CONSTANTS } from './auth.constants';

export interface JwtPayload {
  sub: string;
  email: string;
  role: UserRole;
}

@Injectable()
export class AuthService {
  private readonly saltRounds = 12;

  constructor(
    private readonly prisma: PrismaService,
    private readonly jwtService: JwtService,
  ) {}

  /**
   * Registra un nuevo usuario con email/password
   */
  async register(registerDto: RegisterDto): Promise<TokensResponseDto> {
    const { email, password, name, role = UserRole.USER } = registerDto;

    // Verificar si el usuario ya existe
    const existingUser = await this.prisma.user.findUnique({
      where: { email },
    });

    if (existingUser) {
      throw new ConflictException('El email ya estÃ¡ registrado');
    }

    // Hash de la contraseÃ±a
    const passwordHash = await bcrypt.hash(password, this.saltRounds);

    // Crear usuario
    const user = await this.prisma.user.create({
      data: {
        email,
        name,
        passwordHash,
        role,
        provider: 'LOCAL',
      },
    });

    // Generar tokens
    return this.generateTokens(user);
  }

  /**
   * Autentica un usuario con email/password
   */
  async login(
    loginDto: LoginDto,
    ipAddress?: string,
  ): Promise<TokensResponseDto> {
    const { email, password } = loginDto;

    // Buscar usuario
    const user = await this.prisma.user.findUnique({
      where: { email },
    });

    if (!user) {
      throw new UnauthorizedException('Credenciales invÃ¡lidas');
    }

    // Verificar si el usuario estÃ¡ activo
    if (!user.isActive) {
      throw new ForbiddenException('La cuenta estÃ¡ desactivada');
    }

    // Verificar contraseÃ±a
    const isPasswordValid = await bcrypt.compare(
      password,
      user.passwordHash || '',
    );

    if (!isPasswordValid) {
      throw new UnauthorizedException('Credenciales invÃ¡lidas');
    }

    // Registrar intento de login (para rate limiting)
    if (ipAddress) {
      await this.recordLoginAttempt(user.id, ipAddress, true);
    }

    // Generar tokens
    return this.generateTokens(user);
  }

  /**
   * Genera access y refresh tokens para un usuario
   */
  async generateTokens(user: User): Promise<TokensResponseDto> {
    const payload: JwtPayload = {
      sub: user.id,
      email: user.email,
      role: user.role as UserRole,
    };

    const accessToken = await this.jwtService.signAsync(payload, {
      expiresIn: JWT_CONSTANTS.ACCESS_TOKEN_EXPIRES_IN,
    });

    const refreshToken = await this.jwtService.signAsync(
      { sub: user.id },
      {
        expiresIn: JWT_CONSTANTS.REFRESH_TOKEN_EXPIRES_IN,
      },
    );

    return {
      accessToken,
      refreshToken,
      expiresIn: 15 * 60, // 15 minutos en segundos
      tokenType: 'Bearer',
      user: {
        id: user.id,
        email: user.email,
        name: user.name,
        role: user.role,
      },
    };
  }

  /**
   * Refresca un access token usando un refresh token
   */
  async refreshToken(refreshToken: string): Promise<TokensResponseDto> {
    try {
      const payload = await this.jwtService.verifyAsync<{ sub: string }>(
        refreshToken,
      );

      const user = await this.prisma.user.findUnique({
        where: { id: payload.sub },
      });

      if (!user || !user.isActive) {
        throw new UnauthorizedException('Usuario no encontrado o inactivo');
      }

      return this.generateTokens(user);
    } catch (error) {
      throw new UnauthorizedException('Refresh token invÃ¡lido o expirado');
    }
  }

  /**
   * Registra un intento de login (para rate limiting)
   */
  private async recordLoginAttempt(
    userId: string,
    ipAddress: string,
    success: boolean,
  ): Promise<void> {
    // Log estructurado para auditorÃ­a (en producciÃ³n se enviarÃ­a a un sistema de logging)
    const timestamp = new Date().toISOString();
    const status = success ? 'SUCCESS' : 'FAILURE';

    console.log(
      `[LOGIN_ATTEMPT] ${timestamp} - User: ${userId}, IP: ${ipAddress}, Status: ${status}`,
    );

    // El rate limiting real lo maneja ThrottlerModule a nivel global
    // No hay tabla de login_attempt en el esquema actual, por lo que solo registramos en logs
  }

  /**
   * Valida un usuario por ID (para guards)
   */
  async validateUser(userId: string): Promise<User | null> {
    return this.prisma.user.findUnique({
      where: { id: userId, isActive: true },
    });
  }

  /**
   * Obtiene informaciÃ³n del usuario actual
   */
  async getCurrentUser(userId: string): Promise<Partial<User>> {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
        avatarUrl: true,
        createdAt: true,
        updatedAt: true,
      },
    });

    if (!user) {
      throw new UnauthorizedException('Usuario no encontrado');
    }

    return user;
  }

  /**
   * Actualiza informaciÃ³n del usuario actual
   */
  async updateCurrentUser(
    userId: string,
    data: { name?: string; avatarUrl?: string },
  ): Promise<Partial<User>> {
    const user = await this.prisma.user.update({
      where: { id: userId },
      data: {
        ...(data.name && { name: data.name }),
        ...(data.avatarUrl && { avatarUrl: data.avatarUrl }),
      },
      select: {
        id: true,
        email: true,
        name: true,
        role: true,
        avatarUrl: true,
        createdAt: true,
        updatedAt: true,
      },
    });

    return user;
  }

  /**
   * Genera solo el refresh token (para uso interno en estrategias OAuth)
   */
  async generateRefreshToken(user: User): Promise<string> {
    return this.jwtService.signAsync(
      { sub: user.id },
      {
        expiresIn: JWT_CONSTANTS.REFRESH_TOKEN_EXPIRES_IN,
      },
    );
  }

  /**
   * Obtiene el servicio Prisma (para uso interno en estrategias OAuth)
   */
  getPrisma(): PrismaService {
    return this.prisma;
  }
}

import { Injectable, ExecutionContext } from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { Reflector } from '@nestjs/core';

@Injectable()
export class JwtAuthGuard extends AuthGuard('jwt') {
  constructor(private reflector: Reflector) {
    super();
  }

  canActivate(context: ExecutionContext) {
    // Verificar si la ruta es pÃºblica
    const isPublic = this.reflector.getAllAndOverride<boolean>('isPublic', [
      context.getHandler(),
      context.getClass(),
    ]);

    if (isPublic) {
      return true;
    }

    return super.canActivate(context);
  }

  handleRequest(err: any, user: any, info: any) {
    // Puedes personalizar el manejo de errores aquÃ­
    if (err || !user) {
      throw err || new Error('No autorizado');
    }
    return user;
  }
}

import { Injectable } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { Strategy, VerifyCallback } from 'passport-google-oauth20';
import { AuthService } from '../auth.service';
import { User } from '@prisma/client';
import { AuthProvider } from '../../../shared/enums';

@Injectable()
export class GoogleStrategy extends PassportStrategy(Strategy, 'google') {
  constructor(private readonly authService: AuthService) {
    super({
      clientID: process.env.GOOGLE_CLIENT_ID || 'google-client-id',
      clientSecret: process.env.GOOGLE_CLIENT_SECRET || 'google-client-secret',
      callbackURL:
        process.env.GOOGLE_CALLBACK_URL ||
        'http://localhost:3000/auth/google/callback',
      scope: ['email', 'profile'],
      passReqToCallback: false,
    });
  }

  /**
   * Valida el usuario de Google OAuth
   */
  async validate(
    accessToken: string,
    refreshToken: string,
    profile: any,
    done: VerifyCallback,
  ): Promise<void> {
    try {
      const { id, displayName, emails, photos } = profile;
      const email = emails?.[0]?.value;
      const avatarUrl = photos?.[0]?.value;

      if (!email) {
        return done(new Error('Email no proporcionado por Google'), false);
      }

      // Buscar usuario existente por email
      let user = await this.authService.getPrisma().user.findUnique({
        where: { email },
      });

      if (!user) {
        // Crear nuevo usuario si no existe
        user = await this.authService.getPrisma().user.create({
          data: {
            email,
            name: displayName || email.split('@')[0],
            avatarUrl,
            provider: AuthProvider.GOOGLE,
            role: 'USER', // Rol por defecto para usuarios de Google
            isActive: true,
          },
        });
      } else if (user.provider !== AuthProvider.GOOGLE) {
        // Si el usuario existe pero con otro provider, actualizar
        user = await this.authService.getPrisma().user.update({
          where: { id: user.id },
          data: {
            provider: AuthProvider.GOOGLE,
            avatarUrl: avatarUrl || user.avatarUrl,
          },
        });
      }

      // Retornar el usuario
      done(null, user);
    } catch (error) {
      done(error as Error, false);
    }
  }
}

import { Injectable, UnauthorizedException } from '@nestjs/common';
import { PassportStrategy } from '@nestjs/passport';
import { ExtractJwt, Strategy } from 'passport-jwt';
import { AuthService, JwtPayload } from '../auth.service';
import { User } from '@prisma/client';
import { Request } from 'express';
import { COOKIE_CONSTANTS } from '../auth.constants';

@Injectable()
export class JwtStrategy extends PassportStrategy(Strategy) {
  constructor(private readonly authService: AuthService) {
    super({
      jwtFromRequest: (req: Request) => {
        // 1. Intentar obtener el token del header Authorization
        const authHeader = ExtractJwt.fromAuthHeaderAsBearerToken()(req);
        if (authHeader) {
          return authHeader;
        }

        // 2. Intentar obtener el token de la cookie
        const cookieToken = req.cookies?.[COOKIE_CONSTANTS.ACCESS_TOKEN_NAME];
        if (cookieToken) {
          return cookieToken;
        }

        return null;
      },
      ignoreExpiration: false,
      secretOrKeyProvider: (
        request: any,
        rawJwtToken: string,
        done: (err: any, secret?: string) => void,
      ) => {
        // En producciÃ³n, esto leerÃ­a la clave pÃºblica desde archivo o variable de entorno
        // Por ahora usamos una clave secreta temporal
        const secret =
          process.env.JWT_SECRET || 'temporal-secret-key-for-development';
        done(null, secret);
      },
      algorithms: ['HS256'], // Temporalmente HS256, luego cambiaremos a RS256
    });
  }

  /**
   * Valida el payload del JWT y retorna el usuario
   */
  async validate(payload: JwtPayload): Promise<User> {
    const user = await this.authService.validateUser(payload.sub);

    if (!user) {
      throw new UnauthorizedException('Usuario no encontrado o inactivo');
    }

    return user;
  }
}

