import { ApiProperty } from '@nestjs/swagger';
import {
  IsString,
  IsInt,
  IsOptional,
  IsDecimal,
  IsDateString,
  IsEnum,
  Min,
  Max,
} from 'class-validator';
import { Transform } from 'class-transformer';
import { EventStatus } from '../../../shared/enums';
import { IsBefore } from '../../../shared/validators/is-before.validator';

export class CreateEventDto {
  @ApiProperty({
    example: 'Concierto de Rock',
    description: 'Nombre del evento',
  })
  @IsString()
  name!: string;

  @ApiProperty({ example: 'Un concierto increÃ­ble', required: false })
  @IsOptional()
  @IsString()
  description?: string;

  @ApiProperty({
    example: '2024-12-31T20:00:00Z',
    description: 'Fecha y hora del evento',
  })
  @IsDateString()
