import {
  Injectable,
  NestInterceptor,
  ExecutionContext,
  CallHandler,
} from '@nestjs/common';
import { Observable } from 'rxjs';
import { map } from 'rxjs/operators';

/**
 * Interceptor que transforma objetos Decimal de Prisma a nÃºmeros JavaScript.
 * Prisma devuelve objetos Decimal que no son serializables directamente a JSON.
 */
@Injectable()
export class DecimalInterceptor implements NestInterceptor {
  intercept(context: ExecutionContext, next: CallHandler): Observable<any> {
    return next.handle().pipe(map((data) => this.transformDecimals(data)));
  }

  /**
   * Transforma recursivamente objetos Decimal a nÃºmeros.
   */
  private transformDecimals(data: any): any {
    if (data === null || data === undefined) {
      return data;
    }

    // Si es un objeto Decimal de Prisma
    if (typeof data === 'object' && data !== null) {
      // Verificar si es un objeto Decimal de Prisma (tiene propiedades especÃ­ficas)
      if (this.isPrismaDecimal(data)) {
        return parseFloat(data.toString());
      }

      // Si es un array, transformar cada elemento
      if (Array.isArray(data)) {
        return data.map((item) => this.transformDecimals(item));
      }

      // Si es un objeto regular, transformar cada propiedad
      const transformed: any = {};
      for (const key in data) {
        if (Object.prototype.hasOwnProperty.call(data, key)) {
          transformed[key] = this.transformDecimals(data[key]);
        }
      }
      return transformed;
    }

    // Si no es un objeto, retornar tal cual
    return data;
  }

  /**
   * Verifica si un objeto es un Decimal de Prisma.
   * Los objetos Decimal de Prisma tienen mÃ©todos especÃ­ficos.
   */
  private isPrismaDecimal(obj: any): boolean {
    return (
      typeof obj === 'object' &&
      obj !== null &&
      typeof obj.toString === 'function' &&
      typeof obj.toNumber === 'function' &&
      typeof obj.toFixed === 'function' &&
      !Array.isArray(obj)
    );
  }
}

import {
  registerDecorator,
  ValidationOptions,
  ValidationArguments,
} from 'class-validator';

/**
 * Valida que la propiedad sea anterior a otra propiedad especificada.
 * @param property - Nombre de la propiedad a comparar
 * @param validationOptions - Opciones de validaciÃ³n
 */
export function IsBefore(
  property: string,
  validationOptions?: ValidationOptions,
) {
  return function (object: object, propertyName: string) {
    registerDecorator({
      name: 'isBefore',
      target: object.constructor,
      propertyName: propertyName,
      options: validationOptions,
      constraints: [property],
      validator: {
        validate(value: any, args: ValidationArguments) {
          const [relatedPropertyName] = args.constraints;
          const relatedValue = (args.object as any)[relatedPropertyName];

          // Si alguno de los valores es undefined, no validamos
          if (value === undefined || relatedValue === undefined) {
            return true;
          }

          // Convertir a Date si son strings
          const date1 = new Date(value);
          const date2 = new Date(relatedValue);

          // Validar que sean fechas vÃ¡lidas
          if (isNaN(date1.getTime()) || isNaN(date2.getTime())) {
            return false;
          }

          // La fecha debe ser anterior a la fecha de referencia
          return date1 < date2;
        },
        defaultMessage(args: ValidationArguments) {
          const [relatedPropertyName] = args.constraints;
          return `${args.property} debe ser anterior a ${relatedPropertyName}`;
        },
      },
    });
  };
}

